import pytest

AC_UID = "ac6-20260521-090100-vartemp-demoted-both-files"
AC_TYPE = "data"


def test_AC6():
    """
    GIVEN: commands/codex.md AND /root/.agents/skills/codex/SKILL.md after the change
    WHEN:  Step 2 block is read in each file
    THEN:  /var/tmp/codex-outputs/ appears ONLY in the else/fallback branch (not in the canonical if-branch) in BOTH files; AND the primary/default branch produces a docs/codex/<task_id>/<role>.txt path
    """
    # TODO(dev): replace the line below with the real test body. While the
    # TEST_INCOMPLETE sentinel is present the test will hard-fail, marking
    # the AC as unimplemented for QA Phase 5.
    import os, re
    codex_file = os.path.join(os.path.dirname(__file__), "..", "..", "..", "commands", "codex.md")
    skill_file = "/root/.agents/skills/codex/SKILL.md"

    for filepath in [codex_file, skill_file]:
        assert os.path.exists(filepath), f"File not found: {filepath}"
        with open(filepath) as f:
            content = f.read()

        # Extract Step 2 block (up to Step 3)
        step2_start = content.find("### 2. Generate unique output path")
        step3_start = content.find("### 3. Review mode")
        assert step2_start != -1, f"Step 2 not found in {filepath}"
        step2_block = content[step2_start:step3_start]

        # Extract the bash code block inside Step 2
        bash_match = re.search(r'```bash\n(.*?)```', step2_block, re.DOTALL)
        assert bash_match, f"No bash code block in Step 2 of {filepath}"
        bash_code = bash_match.group(1)

        # Find the if-branch (before else) and else-branch
        else_idx = bash_code.find("\nelse")
        assert else_idx != -1, f"No else branch in Step 2 bash block of {filepath}"
        if_branch = bash_code[:else_idx]
        else_branch = bash_code[else_idx:]

        # /var/tmp/codex-outputs/ must NOT appear in the if-branch (canonical branch)
        # It may appear in the else-branch (fallback)
        assert "/var/tmp/codex-outputs/" not in if_branch, (
            f"{filepath}: /var/tmp/codex-outputs/ appears in canonical if-branch (must be else-only). "
            f"if_branch:\n{if_branch}"
        )
        assert "/var/tmp/codex-outputs/" in else_branch, (
            f"{filepath}: /var/tmp/codex-outputs/ missing from else/fallback branch"
        )

        # Primary/default branch must produce a docs/codex path
        assert "docs/codex/$CODEX_OUT_TASK_ID" in if_branch, (
            f"{filepath}: canonical if-branch does not produce docs/codex/$CODEX_OUT_TASK_ID path"
        )
